	// Regular expressions to extract the title and meta description from HTML.
	titleRe = regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	descRe1 = regexp.MustCompile(`(?i)<meta[^>]+name=["']?description["']?[^>]+content=["']([^"']+)["']`)
	descRe2 = regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']?description["']?`)

	// httpClient is configured as per the requirements.
	httpClient = &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}
)

// FetchURLPreview handles the POST request, fetches the URL, and extracts preview info.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Ensure the request method is POST
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Method not allowed, use POST"})
		return
	}

	// Parse the JSON request body
	var reqData PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqData); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON body"})
		return
	}

	if reqData.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "The 'url' field is required"})
		return
	}

	// Prepare the fasthttp request and response objects
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqData.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Fasthttp-Preview-Fetcher/1.0")

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch the URL using DoRedirects with a maximum of 5 redirects
	err := httpClient.DoRedirects(req, resp, 5)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to fetch URL: " + err.Error()})
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Target URL returned non-200 status code"})
		return
	}

	// Extract Title and Description from the HTML body
	body := resp.Body()
	var title, description string

	if m := titleRe.FindSubmatch(body); len(m) > 1 {
		title = string(bytes.TrimSpace(m[1]))
	}

	if m := descRe1.FindSubmatch(body); len(m) > 1 {
		description = string(bytes.TrimSpace(m[1]))
	} else if m := descRe2.FindSubmatch(body); len(m) > 1 {
		description = string(bytes.TrimSpace(m[1]))
	}

	// Construct and send the successful JSON response
	resData := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(resData)
}

func main() {
	// Simple router for the fasthttp server
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Unsupported path", fasthttp.StatusNotFound)
		}
	}

	log.Println("Server is starting on :8080")
	log.Println("Send a POST request to http://localhost:8080/preview with JSON body: {\"url\": \"https://example.com\"}")

	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

