var httpClient = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

// RequestPayload represents the expected JSON body in the POST request.
type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload represents the JSON response structure.
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// sendJSONResponse is a helper to write JSON responses.
func sendJSONResponse(ctx *fasthttp.RequestCtx, statusCode int, payload ResponsePayload) {
	ctx.SetStatusCode(statusCode)
	body, _ := json.Marshal(payload)
	ctx.SetBody(body)
}

// extractPreview parses HTML body to extract the page title and meta description.
func extractPreview(body []byte) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(bytes.NewReader(body))

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			// End of document or parsing error
			return strings.TrimSpace(title), strings.TrimSpace(description)

		case html.StartTagToken, html.SelfClosingTagToken:
			t := tokenizer.Token()
			if t.Data == "title" {
				tt = tokenizer.Next()
				if tt == html.TextToken {
					title = tokenizer.Token().Data
				}
			} else if t.Data == "meta" {
				var isDesc bool
				var content string
				for _, attr := range t.Attr {
					if strings.EqualFold(attr.Key, "name") && strings.EqualFold(attr.Val, "description") {
						isDesc = true
					}
					if strings.EqualFold(attr.Key, "content") {
						content = attr.Val
					}
				}
				if isDesc && description == "" {
					description = content
				}
			}

		case html.EndTagToken:
			t := tokenizer.Token()
			if t.Data == "head" {
				// Optimization: Stop parsing once the head section ends
				return strings.TrimSpace(title), strings.TrimSpace(description)
			}
		}
	}
}

// FetchURLPreview handles the POST request, fetches the URL, and returns the parsed preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Ensure the request method is POST
	if !ctx.IsPost() {
		sendJSONResponse(ctx, fasthttp.StatusMethodNotAllowed, ResponsePayload{
			Error: "Method not allowed, please use POST",
		})
		return
	}

	// Parse JSON body
	var reqPayload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &reqPayload); err != nil {
		sendJSONResponse(ctx, fasthttp.StatusBadRequest, ResponsePayload{
			Error: "Invalid JSON body",
		})
		return
	}

	// Validate URL field
	if reqPayload.URL == "" {
		sendJSONResponse(ctx, fasthttp.StatusBadRequest, ResponsePayload{
			Error: "The 'url' field is required",
		})
		return
	}

	// Prepare the request and response objects
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqPayload.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// MUST use fasthttp.Client.DoRedirects method to fetch the provided URL
	err := httpClient.DoRedirects(req, resp, 5) // Max 5 redirects
	if err != nil {
		sendJSONResponse(ctx, fasthttp.StatusInternalServerError, ResponsePayload{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	// Check if the response status is 200 OK
	if resp.StatusCode() != fasthttp.StatusOK {
		sendJSONResponse(ctx, fasthttp.StatusBadGateway, ResponsePayload{
			Error: fmt.Sprintf("Received non-200 response from upstream: %d", resp.StatusCode()),
		})
		return
	}

	// Parse HTML to extract title and description
	title, desc := extractPreview(resp.Body())

	// Return the successful JSON response
	sendJSONResponse(ctx, fasthttp.StatusOK, ResponsePayload{
		Title:       title,
		Description: desc,
	})
}

func main() {
	addr := ":8080"
	fmt.Printf("Starting server on %s\n", addr)

	// Start the fasthttp server with the FetchURLPreview handler
	if err := fasthttp.ListenAndServe(addr, FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

