	var reqData PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqData); err != nil {
		sendJSONResponse(ctx, fasthttp.StatusBadRequest, PreviewResponse{Error: "Invalid JSON body"})
		return
