	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqData.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewFetcher/1.0")

	// Fetch the URL using DoRedirects method as required (max 5 redirects)
	err := client.DoRedirects(req, resp, 5)
	if err != nil {
		sendJSONResponse(ctx, fasthttp.StatusInternalServerError, PreviewResponse{Error: "Failed to fetch URL: " + err.Error()})
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		sendJSONResponse(ctx, fasthttp.StatusBadGateway, PreviewResponse{Error: "Target URL returned non-200 status"})
		return
	}

	body := resp.Body()

