// parseHTMLMeta streams through the HTML body to extract the page title and meta description.
func parseHTMLMeta(body []byte) (string, string) {
	var title, description string
	inTitle := false

	tokenizer := html.NewTokenizer(bytes.NewReader(body))
	for {
		tt := tokenizer.Next()
