// Pre-compile regular expressions for HTML parsing to improve performance
var (
	titleRe = regexp.MustCompile(`(?is)<title[^>]*>(.*?)</title>`)
	metaRe  = regexp.MustCompile(`(?is)<meta\s+([^>]+)>`)
	nameRe  = regexp.MustCompile(`(?i)name\s*=\s*["']?description["']?`)
	contRe  = regexp.MustCompile(`(?i)content\s*=\s*["']([^"']+)["']`)
)

// Configure the fasthttp client with DialDualStack as required
var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

// PreviewRequest defines the expected JSON payload
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch and parse URL previews
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Ensure the request method is POST
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Method not allowed, use POST"})
		return
	}

	// Parse the JSON request body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL is required"})
		return
	}

	// Prepare the HTTP request
	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)

	// Prepare the HTTP response
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Fetch the URL following up to 5 redirects
	if err := client.DoRedirects(httpReq, httpResp, 5); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to fetch URL: " + err.Error()})
		return
	}

	// Ensure we got a successful response
	if httpResp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Received non-200 response from the target URL"})
		return
	}

	// Parse the HTML body to extract title and description
	title, desc := extractMeta(httpResp.Body())

	// Send the successful JSON response
	json.NewEncoder(ctx).Encode(PreviewResponse{
		Title:       title,
		Description: desc,
	})
}

// extractMeta uses regular expressions to extract the title and meta description from HTML bytes
func extractMeta(body []byte) (string, string) {
	bodyStr := string(body)
	var title, desc string

	// Extract page title
	if m := titleRe.FindStringSubmatch(bodyStr); len(m) > 1 {
		title = html.UnescapeString(strings.TrimSpace(m[1]))
	}

	// Extract meta description
	for _, m := range metaRe.FindAllStringSubmatch(bodyStr, -1) {
		attrStr := m[1]
		// Check if this meta tag has name="description"
		if nameRe.MatchString(attrStr) {
			// Extract the content attribute
			if cm := contRe.FindStringSubmatch(attrStr); len(cm) > 1 {
				desc = html.UnescapeString(strings.TrimSpace(cm[1]))
				break
			}
		}
	}

	return title, desc
}

func main() {
	// Setup a simple router
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		if string(ctx.Path()) == "/preview" {
			FetchURLPreview(ctx)
		} else {
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	log.Println("Server starting on :8080")
	log.Println("Send a POST request to http://localhost:8080/preview with JSON: {\"url\": \"https://example.com\"}")

	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

