func sendJSONError(ctx *fasthttp.RequestCtx, statusCode int, errMsg string) {
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(ErrorResponse{Error: errMsg})
}

// FetchURLPreview is the handler function to fetch and parse URL previews
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Ensure the request is a POST
	if !ctx.IsPost() {
		sendJSONError(ctx, fasthttp.StatusMethodNotAllowed, "Method not allowed, use POST")
		return
	}

	// Parse the JSON body
	var reqData PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqData); err != nil {
		sendJSONError(ctx, fasthttp.StatusBadRequest, "Invalid JSON body")
		return
	}

	if reqData.URL == "" {
		sendJSONError(ctx, fasthttp.StatusBadRequest, "URL field is required")
		return
	}

	// Prepare fasthttp request and response objects
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqData.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

