// FetchURLPreview handles the POST request, fetches the URL, and extracts the title and meta description.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Ensure the request is a POST request
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		sendJSONResponse(ctx, PreviewResponse{Error: "Method not allowed. Please use POST."})
		return
	}

	// Parse the JSON body
	var reqData PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqData); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, PreviewResponse{Error: "Invalid JSON body."})
		return
	}

	// Validate the URL field
	if reqData.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, PreviewResponse{Error: "The 'url' field is required."})
		return
	}

	// Prepare the request to fetch the target URL
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqData.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	// Prepare the response object
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch the URL with redirects (max 5 redirects) as required
	err := client.DoRedirects(req, resp, 5)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		sendJSONResponse(ctx, PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
		return
	}

	// Check if the remote server returned a successful status
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		sendJSONResponse(ctx, PreviewResponse{Error: fmt.Sprintf("Remote server returned status: %d", resp.StatusCode())})
		return
	}

	// Parse the HTML body to extract title and description
	title, description := extractHTMLPreview(resp.Body())

	// Send successful JSON response
	sendJSONResponse(ctx, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// sendJSONResponse is a helper function to encode and send JSON responses.
func sendJSONResponse(ctx *fasthttp.RequestCtx, respData PreviewResponse) {
	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(respData); err != nil {
		log.Printf("Error encoding JSON response: %v", err)
	}
}

// extractHTMLPreview parses the HTML content and extracts the page title and meta description.
func extractHTMLPreview(body []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		// Extract <title>
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			if title == "" {
				title = n.FirstChild.Data
			}
		}

		// Extract <meta name="description" content="...">
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDescription bool
			var content string
			for _, attr := range n.Attr {
				if strings.EqualFold(attr.Key, "name") && strings.EqualFold(attr.Val, "description") {
					isDescription = true
				}
				if strings.EqualFold(attr.Key, "content") {
					content = attr.Val
				}
			}
			if isDescription && description == "" {
				description = content
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			// Early exit if both are found to optimize parsing
			if title != "" && description != "" {
				return
			}
			traverse(c)
		}
	}

	traverse(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func main() {
	addr := ":8080"
	log.Printf("Starting server on %s", addr)

	// Start the fasthttp server with the FetchURLPreview handler
	if err := fasthttp.ListenAndServe(addr, FetchURLPreview); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

