		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if title == "" {
				title = extractText(n)
			}
		} else if n.Type == html.ElementNode && n.Data == "meta" {
			var isDesc bool
			var content string
			for _, attr := range n.Attr {
				if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
					isDesc = true
				} else if attr.Key == "content" {
					content = attr.Val
				}
			}
			if isDesc && description == "" {
				description = content
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

// extractText recursively extracts text from an HTML node.
func extractText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += extractText(c)
	}
	return result
}

