// ResponsePayload represents the JSON response structure
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview is the handler function that satisfies the requirements
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Ensure the request is a POST request
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		sendJSONResponse(ctx, ResponsePayload{Error: "Method not allowed, please use POST"})
		return
	}

	// Parse the JSON body
	var reqPayload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &reqPayload); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, ResponsePayload{Error: "Invalid JSON body"})
		return
	}

	// Validate the URL field
	if reqPayload.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, ResponsePayload{Error: "The 'url' field is required"})
		return
	}

	// Prepare the request and response objects
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqPayload.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch the URL using DoRedirects with a maximum of 5 redirects
	err := client.DoRedirects(req, resp, 5)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		sendJSONResponse(ctx, ResponsePayload{Error: "Failed to fetch URL: " + err.Error()})
		return
	}

	// Ensure we got a successful response
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		sendJSONResponse(ctx, ResponsePayload{Error: "Target URL returned non-200 status"})
		return
	}

