		}
	}

	// Send the successful JSON response
	sendJSONResponse(ctx, ResponsePayload{
		Title:       title,
		Description: description,
	})
}

// Helper function to send JSON responses
func sendJSONResponse(ctx *fasthttp.RequestCtx, payload ResponsePayload) {
	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(payload); err != nil {
