		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// extractText recursively extracts text content from an HTML node.
func extractText(n *html.Node) string {
	var buf strings.Builder
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.TextNode {
			buf.WriteString(n.Data)
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return buf.String()
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if title == "" {
				title = strings.TrimSpace(extractText(n))
			}
		} else if n.Type == html.ElementNode && n.Data == "meta" {
			var isDesc bool
			var content string
			for _, a := range n.Attr {
				if a.Key == "name" && strings.EqualFold(a.Val, "description") {
					isDesc = true
				} else if a.Key == "content" {
					content = a.Val
				}
			}
			if isDesc && description == "" {
				description = strings.TrimSpace(content)
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description, nil
}

